import React from "react";
import { useNavigate } from "react-router-dom";

function Register() {
  const navigate = useNavigate();

  const handleSubmit = (e) => {
    e.preventDefault();
    navigate("/login");
  };

  return (
    <div className="min-h-screen bg-gray-50 flex items-center justify-center">
      <div className="bg-white w-full max-w-md p-8 rounded-xl shadow-md">

        <h2 className="text-2xl font-semibold text-center text-gray-800">
          Create Account
        </h2>
        <p className="text-center text-gray-500 mb-6">
          Register to continue
        </p>

        <form onSubmit={handleSubmit} className="space-y-4">

          <div>
            <label className="label">Full Name</label>
            <input type="text" placeholder="Enter your name" className="input" required />
          </div>

          <div>
            <label className="label">Email</label>
            <input type="email" placeholder="Enter your email" className="input" required />
          </div>

          <div className="flex gap-3">
            <div className="w-1/2">
              <label className="label">DOB</label>
              <input type="date" className="input" required />
            </div>

            <div className="w-1/2">
              <label className="label">Gender</label>
              <select className="input" required>
                <option value="">Select</option>
                <option>Male</option>
                <option>Female</option>
                <option>Other</option>
              </select>
            </div>
          </div>

          <div>
            <label className="label">Address</label>
            <textarea placeholder="Enter your address" className="input" required />
          </div>

          <div>
            <label className="label">Phone</label>
            <input type="tel" placeholder="Enter phone number" className="input" required />
          </div>

          <div>
            <label className="label">Password</label>
            <input type="password" placeholder="Enter password" className="input" required />
          </div>

          <div>
            <label className="label">Confirm Password</label>
            <input type="password" placeholder="Confirm password" className="input" required />
          </div>

          <button className="w-full bg-gray-800 text-white py-2.5 rounded-lg font-medium hover:bg-gray-700 transition">
            Sign Up
          </button>
        </form>

        <p className="text-center text-sm mt-4 text-gray-600">
          Already have an account?
          <span
            onClick={() => navigate("/login")}
            className="ml-1 text-gray-800 font-medium cursor-pointer"
          >
            Login
          </span>
        </p>
      </div>

      <style>
        {`
        .input {
          width: 100%;
          padding: 10px;
          border: 1px solid #e5e7eb;
          border-radius: 6px;
          margin-top: 4px;
          font-size: 14px;
        }

        .input:focus {
          outline: none;
          border-color: #111827;
        }

        .label {
          font-size: 13px;
          color: #374151;
        }
        `}
      </style>
    </div>
  );
}

export default Register;
